    }

    def __init__(self, session: Session):
        super().__init__(session)

    def fetch_events(self, last_id="0"):
        # 씨네Q는 eventId=0으로 시작하여 더보기 방식으로 호출함
        payload = {
            "eventId": last_id,
            "eventSort": "-1" # 최신순
        }
